'use client';

import { useState } from 'react';
import Link from 'next/link';
import { useRouter, useSearchParams } from 'next/navigation';
import { Button } from '@/components/ui/button';
import { Input } from '@/components/ui/input';
import { Label } from '@/components/ui/label';
import { Logo } from '@/components/logo';
import { AlertCircle, Loader2, ShieldCheck, Mail, Lock, ArrowRight } from 'lucide-react';
import { Alert, AlertDescription } from '@/components/ui/alert';
import { motion, AnimatePresence } from 'framer-motion';
import { AnimatedBg } from '@/components/ui-patterns/animated-bg';

export default function LoginPage() {
  const router = useRouter();
  const searchParams = useSearchParams();
  const [email, setEmail] = useState('');
  const [password, setPassword] = useState('');
  const [error, setError] = useState('');
  const [isLoading, setIsLoading] = useState(false);

  const from = searchParams.get('from') || '/portal';
  const isAdminLogin = from.startsWith('/admin');

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    setError('');
    setIsLoading(true);

    try {
      const res = await fetch('/api/auth/login', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ email, password }),
      });

      const data = await res.json();

      if (!res.ok) {
        throw new Error(data.error || 'Something went wrong');
      }

      router.push(from);
      router.refresh();
    } catch (err: any) {
      setError(err.message);
    } finally {
      setIsLoading(false);
    }
  };

  return (
    <div className="relative min-h-screen flex items-center justify-center px-4 py-20 overflow-hidden bg-[#f8fafc] dark:bg-[#020617] selection:bg-brand selection:text-white">
      <AnimatedBg />

      <motion.div
        initial={{ opacity: 0, scale: 0.95 }}
        animate={{ opacity: 1, scale: 1 }}
        transition={{ duration: 0.5, ease: "easeOut" }}
        className="w-full max-w-xl z-10"
      >
        <div className="text-center mb-10 space-y-4">
          <motion.div
            initial={{ y: -20, opacity: 0 }}
            animate={{ y: 0, opacity: 1 }}
            transition={{ delay: 0.2 }}
          >
            <Logo className="justify-center mb-10" />
          </motion.div>
          <h1 className="text-5xl font-black text-brand-dark dark:text-white tracking-tighter uppercase leading-none">
            {isAdminLogin ? 'Nexus' : 'Secure'} <span className="text-brand">Portal</span>
          </h1>
          <p className="text-muted-foreground font-medium text-lg">
            {isAdminLogin 
              ? 'Authorized administrative infrastructure access.' 
              : 'Enterprise resource management & project tracking.'}
          </p>
        </div>

        <div className="glass-card p-12 rounded-[3.5rem] relative overflow-hidden shadow-2xl border-white/20 dark:border-white/5 bg-white/70 dark:bg-slate-900/40 backdrop-blur-2xl">
          {isAdminLogin && (
            <div className="absolute top-0 left-1/2 -translate-x-1/2 px-6 py-1.5 rounded-b-2xl bg-brand/10 border-x border-b border-brand/20 flex items-center gap-2">
              <ShieldCheck className="h-3.5 w-3.5 text-brand animate-pulse" />
              <span className="text-[9px] font-black uppercase tracking-[0.3em] text-brand">Secure Management Console</span>
            </div>
          )}

          <AnimatePresence mode="wait">
            {error && (
              <motion.div 
                initial={{ height: 0, opacity: 0, marginBottom: 0 }} 
                animate={{ height: 'auto', opacity: 1, marginBottom: 24 }} 
                exit={{ height: 0, opacity: 0, marginBottom: 0 }}
                className="overflow-hidden"
              >
                <Alert variant="destructive" className="border-destructive/20 bg-destructive/5 rounded-2xl py-4">
                  <AlertCircle className="h-4 w-4" />
                  <AlertDescription className="font-bold text-xs uppercase tracking-tight">{error}</AlertDescription>
                </Alert>
              </motion.div>
            )}
          </AnimatePresence>

          <form onSubmit={handleSubmit} className="space-y-8">
            <div className="space-y-3">
              <Label className="text-[10px] font-black uppercase tracking-[0.3em] text-brand-dark dark:text-slate-400 ml-1">Identity Protocol (Email)</Label>
              <div className="relative group">
                <div className="absolute left-5 top-1/2 -translate-y-1/2 h-5 w-5 text-brand transition-transform group-focus-within:scale-110">
                  <Mail className="h-full w-full" />
                </div>
                <Input
                  type="email"
                  placeholder="identity@enterprise.com"
                  value={email}
                  onChange={(e) => setEmail(e.target.value)}
                  required
                  disabled={isLoading}
                  className="h-16 bg-brand/5 border-brand/10 pl-14 rounded-2xl focus:bg-white dark:focus:bg-slate-900 focus:ring-4 focus:ring-brand/5 transition-all font-bold text-brand-dark dark:text-white placeholder:text-muted-foreground/60"
                />
              </div>
            </div>

            <div className="space-y-3">
              <div className="flex items-center justify-between ml-1">
                <Label className="text-[10px] font-black uppercase tracking-[0.3em] text-brand-dark dark:text-slate-400">Security Key (Password)</Label>
                <Link href="/forgot-password" size="sm" className="text-[9px] font-black uppercase text-brand hover:underline tracking-widest">
                  Reset Key
                </Link>
              </div>
              <div className="relative group">
                <div className="absolute left-5 top-1/2 -translate-y-1/2 h-5 w-5 text-brand transition-transform group-focus-within:scale-110">
                  <Lock className="h-full w-full" />
                </div>
                <Input 
                  type="password" 
                  value={password}
                  onChange={(e) => setPassword(e.target.value)}
                  required 
                  disabled={isLoading}
                  className="h-16 bg-brand/5 border-brand/10 pl-14 rounded-2xl focus:bg-white dark:focus:bg-slate-900 focus:ring-4 focus:ring-brand/5 transition-all font-bold text-brand-dark dark:text-white"
                />
              </div>
            </div>

            <Button 
              type="submit" 
              className="w-full h-16 bg-brand hover:bg-brand/90 text-white font-black uppercase tracking-[0.2em] shadow-2xl shadow-brand/20 rounded-2xl transition-all active:scale-[0.98] text-sm group" 
              disabled={isLoading}
            >
              {isLoading ? (
                <>
                  <Loader2 className="mr-3 h-5 w-5 animate-spin" />
                  Verifying Identity...
                </>
              ) : (
                <div className="flex items-center justify-center gap-3">
                  {isAdminLogin ? 'Unlock Nexus' : 'Initialize Access'}
                  <ArrowRight className="h-5 w-5 transition-transform group-hover:translate-x-1" />
                </div>
              )}
            </Button>
          </form>

          <div className="mt-12 pt-8 border-t border-brand/10 text-center">
            <p className="text-[10px] font-bold text-muted-foreground uppercase tracking-[0.2em]">
              New to the ecosystem?{' '}
              <Link href="/register" className="font-black text-brand hover:underline">
                Request Authorization
              </Link>
            </p>
          </div>
        </div>

        <motion.p 
          initial={{ opacity: 0 }}
          animate={{ opacity: 1 }}
          transition={{ delay: 0.5 }}
          className="mt-8 text-center text-[9px] font-black text-slate-400 uppercase tracking-[0.3em] pointer-events-none"
        >
          © 2026 CYROTICS TECHNOLOGY CORP. ALL RIGHTS RESERVED.
        </motion.p>
      </motion.div>
    </div>
  );
}
